class Solution:
    def wordCount(self, startWords: List[str], targetWords: List[str]) -> int:
        start_set = set(''.join(sorted(word)) for word in startWords)
        count = 0
        for word in targetWords:
            for i in range(26):
                c = chr(ord('a') + i)
                if c not in word:
                    if ''.join(sorted(word + c)) in start_set:
                        count += 1
                        break
        return count
